// ─────────────────────────────────────────────
// VHSYS :: nf_service_labels_ids
// Rota   : GET /nf_service_labels_ids
// Fase 5 : Fluxos NF
// ─────────────────────────────────────────────
// Input  : Nenhum (GET)
// Output : [{ codigo_servico, descricao, aliquota_iss, ativo }] HTTP 200
// Banco  : SELECT nf_service_labels WHERE ativo = true
// ─────────────────────────────────────────────
// CRÍTICO: Retorna ARRAY DIRETO — NÃO encapsulado
// A extensão Chrome espera: [...] não { data: [...] }
// ─────────────────────────────────────────────

const allRecords = $input.all();
const labels = allRecords.map(item => item.json);

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'nf_service_labels_ids',
  event: 'labels_read',
  total_labels: labels.length,
  level: 'info'
}));

// statusCode 200 para GET (não 201)
return {
  statusCode: 200,
  body: labels
};

// Erro de leitura do banco
const errData = $input.first().json;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'nf_service_labels_ids',
  event: 'db_read_error',
  message: errData.message || 'Unknown DB error',
  level: 'error'
}));

return {
  statusCode: 500,
  body: { ok: false, error: 'Database read error', message: 'Could not read service labels' }
};

// Return the response data as-is
const response = $input.first().json;
return response;
